const body = $json.body ?? {};
const onlyDigits = (value) => String(value ?? '').replace(/\D/g, '');
const normalizeBrazilPhone = (value) => {
  const digits = onlyDigits(value);
  if (digits.length === 10 || digits.length === 11) return `55${digits}`;
  return digits;
};
const chatId = String(body.chat_id ?? body.from ?? body.customer_phone ?? '').replace(/\s+/g, '').trim();
const msg = String(body.text ?? body.message ?? '').replace(/\s+/g, ' ').trim();
return {
  tenant_id: body.tenant_id || null,
  tenant_phone_e164: normalizeBrazilPhone(body.tenant_phone_e164 ?? body.to ?? body.receiver ?? ''),
  customer_phone_e164: normalizeBrazilPhone(body.customer_phone_e164 ?? body.from ?? body.chat_id ?? ''),
  chat_id: chatId,
  msg,
  raw_body: body
};

const row = Array.isArray($json) ? $json[0] : $json;
const msg = String($node.Normalize.json.msg ?? '').trim();
const customerPhone = String($node.Normalize.json.customer_phone_e164 ?? '').trim();
const payload = row.payload_draft ?? {};
const draft = payload.appointment ?? {};
const services = Array.isArray(row.services) ? row.services : [];
const staff = Array.isArray(row.staff_members) ? row.staff_members : [];
const upcomingAppointments = Array.isArray(row.upcoming_appointments) ? row.upcoming_appointments : [];
const step = row.step || 'appointment_welcome';
const tenantName = row.tenant_name || 'nossa equipe';

function reply(text, nextStep, patch = {}, close = false) {
  return [{ json: { action: 'patch', reply: text, conversation_id: row.conversation_id, next_step: nextStep, p_close: close, data_patch: { appointment: { ...patch, customer_whatsapp: customerPhone || draft.customer_whatsapp || null }, metadata: { last_step: nextStep, updated_at: new Date().toISOString() } } } }];
}

function suggestSlots(nextStep, patch = {}) {
  const merged = { ...draft, ...patch };
  return [{ json: { action: 'suggest_slots', conversation_id: row.conversation_id, next_step: nextStep, p_close: false, data_patch: { appointment: { ...merged, customer_whatsapp: customerPhone || draft.customer_whatsapp || null }, metadata: { last_step: nextStep, updated_at: new Date().toISOString() } }, suggest_body: { p_tenant_id: row.tenant_id, p_service_id: merged.service_id, p_staff_member_id: merged.staff_member_id || null, p_from_date: merged.from_date || new Date().toLocaleDateString('en-CA', { timeZone: 'America/Fortaleza' }), p_period: merged.period || null, p_limit: 5, p_offset: Number(merged.slot_offset || 0), p_days_ahead: 60, p_timezone: 'America/Fortaleza' } } }];
}

function createAppointment() {
  const service = services.find((item) => item.id === draft.service_id) ?? null;
  const staffMember = staff.find((item) => item.id === draft.staff_member_id) ?? null;
  return [{ json: { action: 'create', conversation_id: row.conversation_id, next_step: 'appointment_done', p_close: true, create_body: { p_tenant_id: row.tenant_id, p_full_name: draft.full_name, p_cpf: draft.cpf, p_whatsapp_e164: customerPhone || draft.customer_whatsapp, p_birth_date: draft.birth_date, p_service_id: draft.service_id || null, p_staff_member_id: draft.staff_member_id || null, p_starts_at: draft.starts_at, p_ends_at: draft.ends_at, p_title: service ? service.name : 'Agendamento via WhatsApp', p_notes: 'Criado via WhatsApp' + (staffMember ? ' com ' + staffMember.name : '') + '.' } } }];
}

function applyAppointmentAction(action, patch = {}) {
  const merged = { ...draft, ...patch };
  return [{ json: { action: 'apply_action', conversation_id: row.conversation_id, next_step: action === 'reschedule' ? 'appointment_rescheduled' : 'appointment_done', p_close: true, applied_action: action, apply_body: { p_appointment_id: merged.appointment_id, p_action: action, p_new_starts_at: merged.starts_at || null, p_new_ends_at: merged.ends_at || null, p_note: 'Alteracao solicitada pelo cliente via WhatsApp.' }, data_patch: { appointment: { ...merged, customer_whatsapp: customerPhone || draft.customer_whatsapp || null }, metadata: { last_step: 'appointment_done', updated_at: new Date().toISOString() } } } }];
}

function parseCpf(value) {
  const cpf = String(value ?? '').replace(/\D/g, '');
  if (cpf.length !== 11 || /^(\d)\1{10}$/.test(cpf)) return null;
  return cpf;
}

function parseDateBR(value) {
  const match = String(value ?? '').trim().match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (!match) return null;
  const iso = match[3] + '-' + match[2].padStart(2, '0') + '-' + match[1].padStart(2, '0');
  const date = new Date(iso + 'T00:00:00-03:00');
  if (Number.isNaN(date.getTime())) return null;
  return iso;
}

function periodFromMessage(value) {
  const normalized = String(value ?? '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
  if (['1', 'manha', 'morning'].includes(normalized)) return { key: 'morning', label: 'manha' };
  if (['2', 'tarde', 'afternoon'].includes(normalized)) return { key: 'afternoon', label: 'tarde' };
  if (['3', 'noite', 'night'].includes(normalized)) return { key: 'night', label: 'noite' };
  if (['4', 'qualquer', 'primeiro', 'primeiro horario', 'any'].includes(normalized)) return { key: 'any', label: 'primeiro horario livre' };
  return null;
}

function renderServiceMenu() {
  if (!services.length) return 'Ainda nao ha servicos cadastrados para este tenant. Fale com a equipe para configurar a agenda.';
  return 'Escolha o servico:\n' + services.map((service, index) => String(index + 1) + ') ' + service.name + (service.duration_minutes ? ' - ' + service.duration_minutes + 'min' : '')).join('\n');
}

function staffForService(serviceId) {
  const service = services.find((item) => item.id === serviceId) ?? null;
  const linkedIds = Array.isArray(service?.staff_member_ids) ? service.staff_member_ids : [];
  return staff.filter((member) => linkedIds.includes(member.id));
}

function renderStaffMenu(candidates = staffForService(draft.service_id)) {
  if (!candidates.length) return 'Ainda nao ha profissionais vinculados a este servico. Fale com a equipe para configurar a agenda.';
  return 'Escolha o profissional:\n' + candidates.map((member, index) => String(index + 1) + ') ' + member.name).join('\n');
}

function continueAfterServiceSelection(selected, baseDraft) {
  const candidates = staffForService(selected.id);
  const nextDraft = { ...baseDraft, service_id: selected.id, service_name: selected.name, duration_minutes: selected.duration_minutes };
  if (!candidates.length) return reply(renderStaffMenu(candidates), 'choose_service', draft);
  if (candidates.length === 1) {
    const only = candidates[0];
    return reply(renderPeriodMenu(), 'choose_period', { ...nextDraft, staff_member_id: only.id, staff_member_name: only.name, slot_offset: 0 });
  }
  return reply(renderStaffMenu(candidates), 'choose_staff', nextDraft);
}

function renderPeriodMenu(prefix = 'Qual periodo voce prefere?') {
  return prefix + '\n1) Manha\n2) Tarde\n3) Noite\n4) Primeiro horario livre';
}

function pickSlot(value) {
  const index = Number(value) - 1;
  const slots = Array.isArray(draft.available_slots) ? draft.available_slots : [];
  return slots[index] ?? null;
}

function normalizeAction(value) {
  return String(value ?? '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
}

function renderMainMenu(welcome = '') {
  const prefix = welcome ? welcome + '\n\n' : '';
  return prefix + 'O que deseja fazer?\n1) Agendar\n2) Remarcar agendamento\n3) Cancelar agendamento';
}

function renderExistingAppointmentMenu(actionLabel) {
  if (!upcomingAppointments.length) return 'Nao encontrei agendamentos futuros para este WhatsApp. Fale com a equipe para ' + actionLabel + '.';
  return 'Escolha qual agendamento deseja ' + actionLabel + ':\n' + upcomingAppointments.map((appointment, index) => String(index + 1) + ') ' + appointment.label).join('\n');
}

function pickExistingAppointment(value) {
  const index = Number(value) - 1;
  return upcomingAppointments[index] ?? null;
}

function actionFromMessage(value) {
  const normalized = normalizeAction(value);
  if (['1', 'agendar', 'agenda', 'marcar', 'novo', 'novo agendamento'].includes(normalized)) return 'schedule';
  if (['2', 'remarcar', 'reagendar', 'mudar horario', 'alterar'].includes(normalized)) return 'reschedule';
  if (['3', 'cancelar', 'cancelamento', 'desmarcar'].includes(normalized)) return 'cancel';
  return null;
}

function startExistingAppointmentAction(action) {
  const actionLabel = action === 'cancel' ? 'cancelar' : 'remarcar';
  if (!upcomingAppointments.length) return reply('Nao encontrei agendamentos futuros para este WhatsApp. Fale com a equipe para ' + actionLabel + '.', 'appointment_done', draft, true);
  if (upcomingAppointments.length === 1) {
    const appointment = upcomingAppointments[0];
    return reply('Para ' + actionLabel + ' este agendamento, confirme sua data de nascimento no formato DD/MM/AAAA.\n\n' + appointment.label, 'confirm_existing_appointment_identity', { ...draft, pending_action: action, appointment_id: appointment.appointment_id, customer_birth_date: appointment.customer_birth_date, service_id: appointment.service_id, service_name: appointment.service_name, staff_member_id: appointment.staff_member_id, staff_member_name: appointment.staff_member_name, duration_minutes: appointment.duration_minutes, slot_offset: 0 });
  }
  return reply(renderExistingAppointmentMenu(actionLabel), 'choose_existing_appointment', { ...draft, pending_action: action });
}

if (!msg && step !== 'appointment_welcome') return reply('Nao recebi nenhuma mensagem. Pode enviar novamente?', step, draft);

if (step === 'appointment_confirmation_action') {
  const normalized = msg.toLowerCase();
  if (['1', 'confirmar', 'confirmo', 'sim', 's'].includes(normalized)) return applyAppointmentAction('confirm');
  if (['3', 'cancelar', 'cancela'].includes(normalized)) return applyAppointmentAction('cancel');
  if (['2', 'remarcar'].includes(normalized)) return reply('Claro. Para remarcar, confirme sua data de nascimento no formato DD/MM/AAAA.', 'reschedule_confirm_identity', { ...draft, reschedule: true, slot_offset: 0 });
  return reply('Responda 1 para confirmar, 2 para remarcar ou 3 para cancelar.', step, draft);
}

if (['menu', '0', 'inicio', 'iniciar'].includes(normalizeAction(msg)) || step === 'appointment_welcome') {
  const welcome = String(row.welcome_message || '').replaceAll('{{tenant_name}}', tenantName);
  return reply(renderMainMenu(welcome), 'choose_appointment_action', {});
}

if (step === 'choose_appointment_action') {
  const action = actionFromMessage(msg);
  if (!action) return reply(renderMainMenu('Nao entendi sua escolha.'), step, draft);
  if (action === 'schedule') return reply('Perfeito. Para comecar, envie seu nome completo.', 'collect_full_name', draft);
  return startExistingAppointmentAction(action);
}

if (step === 'choose_existing_appointment') {
  const appointment = pickExistingAppointment(msg);
  const action = draft.pending_action === 'cancel' ? 'cancel' : 'reschedule';
  const actionLabel = action === 'cancel' ? 'cancelar' : 'remarcar';
  if (!appointment) return reply(renderExistingAppointmentMenu(actionLabel), step, draft);
  return reply('Para ' + actionLabel + ' este agendamento, confirme sua data de nascimento no formato DD/MM/AAAA.\n\n' + appointment.label, 'confirm_existing_appointment_identity', { ...draft, pending_action: action, appointment_id: appointment.appointment_id, customer_birth_date: appointment.customer_birth_date, service_id: appointment.service_id, service_name: appointment.service_name, staff_member_id: appointment.staff_member_id, staff_member_name: appointment.staff_member_name, duration_minutes: appointment.duration_minutes, slot_offset: 0 });
}

if (step === 'confirm_existing_appointment_identity') {
  const birthDate = parseDateBR(msg);
  if (!birthDate) return reply('Data invalida. Envie no formato DD/MM/AAAA para confirmar sua identidade.', step, draft);
  if (draft.customer_birth_date && birthDate !== draft.customer_birth_date) {
    return reply('Nao consegui confirmar sua identidade. Fale com a equipe para alterar este agendamento.', 'appointment_done', draft, true);
  }
  if (draft.pending_action === 'cancel') return applyAppointmentAction('cancel', draft);
  return reply(renderPeriodMenu('Identidade confirmada. Para remarcar, escolha um periodo:'), 'reschedule_choose_period', { ...draft, identity_confirmed: true });
}

if (step === 'collect_full_name') {
  const name = msg.replace(/\s+/g, ' ').trim();
  if (name.split(' ').filter(Boolean).length < 2) return reply('Me informe seu nome completo, por favor. Ex: Joao Silva.', step, draft);
  return reply('Perfeito. Agora envie seu CPF com 11 digitos.', 'collect_cpf', { ...draft, full_name: name });
}

if (step === 'collect_cpf') {
  const cpf = parseCpf(msg);
  if (!cpf) return reply('CPF invalido. Envie apenas os 11 digitos.', step, draft);
  return reply('Agora envie sua data de nascimento no formato DD/MM/AAAA.', 'collect_birth_date', { ...draft, cpf });
}

if (step === 'collect_birth_date') {
  const birthDate = parseDateBR(msg);
  if (!birthDate) return reply('Data invalida. Envie no formato DD/MM/AAAA.', step, draft);
  const nextDraft = { ...draft, birth_date: birthDate };
  if (services.length === 1) return continueAfterServiceSelection(services[0], nextDraft);
  return reply(renderServiceMenu(), 'choose_service', nextDraft);
}

if (step === 'reschedule_confirm_identity') {
  const birthDate = parseDateBR(msg);
  if (!birthDate) return reply('Data invalida. Envie no formato DD/MM/AAAA para confirmar sua identidade.', step, draft);
  if (draft.customer_birth_date && birthDate !== draft.customer_birth_date) {
    return reply('Nao consegui confirmar sua identidade. Fale com a equipe para remarcar este horario.', 'appointment_done', draft, true);
  }
  return reply(renderPeriodMenu('Identidade confirmada. Para remarcar, escolha um periodo:'), 'reschedule_choose_period', { ...draft, identity_confirmed: true });
}

if (step === 'choose_service') {
  if (!services.length) return reply(renderServiceMenu(), step, draft);
  const selected = services[Number(msg) - 1];
  if (!selected) return reply(renderServiceMenu(), step, draft);
  return continueAfterServiceSelection(selected, draft);
}

if (step === 'choose_staff') {
  const candidates = staffForService(draft.service_id);
  const selected = candidates[Number(msg) - 1];
  if (!selected) return reply(renderStaffMenu(candidates), step, draft);
  return reply(renderPeriodMenu(), 'choose_period', { ...draft, staff_member_id: selected.id, staff_member_name: selected.name, slot_offset: 0 });
}

if (step === 'choose_period' || step === 'reschedule_choose_period') {
  const period = periodFromMessage(msg);
  if (!period) return reply(renderPeriodMenu('Nao entendi. Escolha um periodo:'), step, draft);
  const nextStep = step === 'reschedule_choose_period' ? 'reschedule_select_slot' : 'select_slot';
  return suggestSlots(nextStep, { ...draft, period: period.key, period_label: period.label, slot_offset: 0 });
}

if (step === 'select_slot' || step === 'reschedule_select_slot') {
  const normalized = msg.toLowerCase();
  if (['mais', 'mais opcoes', 'mais op??es', 'm'].includes(normalized)) {
    const currentSlots = Array.isArray(draft.available_slots) ? draft.available_slots : [];
    return suggestSlots(step, { ...draft, slot_offset: Number(draft.slot_offset || 0) + currentSlots.length });
  }
  const slot = pickSlot(msg);
  if (!slot) return reply('Escolha uma das opcoes pelo numero ou envie *mais* para ver outros horarios.', step, draft);
  if (step === 'reschedule_select_slot') {
    return applyAppointmentAction('reschedule', { ...draft, starts_at: slot.starts_at, ends_at: slot.ends_at, staff_member_id: slot.staff_member_id || draft.staff_member_id || null, staff_member_name: slot.staff_member_name || draft.staff_member_name || null });
  }
  const summary = 'Confirme seu agendamento:\n\nNome: ' + draft.full_name + '\nServico: ' + (draft.service_name || '-') + '\nProfissional: ' + (slot.staff_member_name || draft.staff_member_name || 'Sem preferencia') + '\nHorario: ' + slot.label + '\n\nResponda *sim* para confirmar ou *0* para recomecar.';
  return reply(summary, 'confirm_appointment', { ...draft, starts_at: slot.starts_at, ends_at: slot.ends_at, staff_member_id: slot.staff_member_id || draft.staff_member_id || null, staff_member_name: slot.staff_member_name || draft.staff_member_name || null, selected_slot_label: slot.label });
}

if (step === 'confirm_appointment') {
  if (!['sim', 's', 'confirmar', 'confirmo'].includes(msg.toLowerCase())) return reply('Tudo bem. Envie 0 para recomecar ou responda *sim* para confirmar os dados acima.', step, draft);
  return createAppointment();
}

return reply('Vamos recomecar. Me informe seu nome completo.', 'collect_full_name', {});

const appointmentId = $json.data ?? $json.body ?? $json;
return [{ json: {
  reply: 'Agendamento confirmado! Em breve a equipe pode falar com voce por aqui se precisar ajustar algo.',
  conversation_id: $node.FN_appointment_state_machine.json.conversation_id,
  next_step: 'appointment_done',
  p_close: true,
  data_patch: {
    appointment: {
      appointment_id: Array.isArray(appointmentId) ? appointmentId[0] : appointmentId
    },
    metadata: {
      completed_at: new Date().toISOString()
    }
  }
}}];

const inputItems = typeof $input !== 'undefined' ? $input.all().map((item) => item.json) : [$json];
const slots = inputItems.filter((item) => item && item.starts_at && item.ends_at);
const original = $node.FN_appointment_state_machine.json;
const previousPatch = original.data_patch?.appointment ?? {};
const nextStep = original.next_step;
if (!slots.length) {
  return [{ json: { action: 'patch', reply: 'Nao encontrei horarios livres nesse periodo. Envie *mais* para procurar adiante ou escolha outro periodo: 1 manha, 2 tarde, 3 noite, 4 primeiro horario livre.', conversation_id: original.conversation_id, next_step: nextStep, p_close: false, data_patch: original.data_patch } }];
}
const lines = slots.map((slot, index) => String(index + 1) + ') ' + slot.label);
return [{ json: { action: 'patch', reply: 'Encontrei estes horarios:\n' + lines.join('\n') + '\n\nResponda o numero desejado ou envie *mais* para ver outras opcoes.', conversation_id: original.conversation_id, next_step: nextStep, p_close: false, data_patch: { ...original.data_patch, appointment: { ...previousPatch, available_slots: slots.map((slot) => ({ starts_at: slot.starts_at, ends_at: slot.ends_at, label: slot.label, staff_member_id: slot.staff_member_id, staff_member_name: slot.staff_member_name })) } } } }];

const original = $node.FN_appointment_state_machine.json;
const action = original.applied_action;
const replyByAction = { confirm: 'Horario confirmado. Obrigado! Esperamos voce no dia combinado.', cancel: 'Agendamento cancelado. Se precisar marcar outro horario, envie *menu*.', reschedule: 'Horario remarcado com sucesso. Obrigado!' };
return [{ json: { reply: replyByAction[action] || 'Agendamento atualizado com sucesso.', conversation_id: original.conversation_id, next_step: original.next_step, p_close: true, data_patch: original.data_patch } }];
